with open('/tmp/20250602_064026_result.json', 'r') as f:
    businesses = json.load(f)
print(f"Total businesses loaded: {len(businesses)}")
wifi_businesses = []
for b in businesses:
    if isinstance(b.get('attributes'), dict) and b['attributes'].get('WiFi'):
        wifi_value = str(b['attributes']['WiFi']).lower()
        if 'yes' in wifi_value or 'free' in wifi_value:
            # Extract state from description
            desc = b.get('description', '')
            # Look for state pattern: 2-letter state code at end of location
            import re
            match = re.search(r'\b([A-Z]{2})\b', desc)
            if match:
                state = match.group(1)
                if state in ['AL', 'AK', 'AZ', 'AR', 'CA', 'CO', 'CT', 'DE', 'FL', 'GA', 'HI', 'ID', 'IL', 'IN', 'IA', 'KS', 'KY', 'LA', 'ME', 'MD', 'MA', 'MI', 'MN', 'MS', 'MO', 'MT', 'NE', 'NV', 'NH', 'NJ', 'NM', 'NY', 'NC', 'ND', 'OH', 'OK', 'OR', 'PA', 'RI', 'SC', 'SD', 'TN', 'TX', 'UT', 'VT', 'VA', 'WA', 'WV', 'WI', 'WY']:
                    wifi_businesses.append({
                        'business_id': b['business_id'],
                        'name': b['name'],
                        'state': state,
                        'wifi': b['attributes']['WiFi']
                    })
print(f"Businesses with WiFi: {len(wifi_businesses)}")
if wifi_businesses:
    print("Sample WiFi businesses:")
    for wb in wifi_businesses[:5]:
        print(wb)
print('__RESULT__:')
print(json.dumps(wifi_businesses[:100]))  # Return first 100 for now"}

